<div class="modal-body clearfix"><div class="container-fluid">
    <input type="hidden" name="id" value="<?php echo $id; ?>"><input type="hidden" name="account_id" value="<?php echo (int) $account_id; ?>"><input type="hidden" name="duplicate_override" value="0">
    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_address_type"); ?></label><div class="col-md-9"><select name="address_type" class="form-control"><?php foreach ($types as $option) { ?><option value="<?php echo $e($option["id"]); ?>"<?php echo ($model_info->address_type ?? "main") === $option["id"] ? " selected" : ""; ?>><?php echo $e($option["text"]); ?></option><?php } ?></select></div></div></div>
    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_postal_code"); ?></label><div class="col-md-3"><?php echo form_input(["name" => "postal_code", "value" => $model_info->postal_code ?? "", "class" => "form-control", "maxlength" => 20]); ?></div><label class="col-md-2"><?php echo app_lang("gd_street"); ?></label><div class="col-md-4"><?php echo form_input(["name" => "street", "value" => $model_info->street ?? "", "class" => "form-control", "maxlength" => 190]); ?></div></div></div>
