    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_district"); ?></label><div class="col-md-3"><?php echo form_input(["name" => "district", "value" => $model_info->district ?? "", "class" => "form-control", "maxlength" => 120]); ?></div><label class="col-md-2"><?php echo app_lang("gd_city"); ?></label><div class="col-md-4"><?php echo form_input(["name" => "city", "value" => $model_info->city ?? "", "class" => "form-control", "maxlength" => 120]); ?></div></div></div>
    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_state"); ?></label><div class="col-md-3"><?php echo form_input(["name" => "state", "value" => $model_info->state ?? "", "class" => "form-control", "maxlength" => 80]); ?></div><label class="col-md-2"><?php echo app_lang("gd_country"); ?></label><div class="col-md-4"><?php echo form_input(["name" => "country", "value" => $model_info->country ?? "", "class" => "form-control", "maxlength" => 80]); ?></div></div></div>
    <div class="form-group"><div class="row"><label class="col-md-3"><?php echo app_lang("gd_flags"); ?></label><div class="col-md-9"><?php echo form_checkbox("is_primary", "1", !empty($model_info->is_primary)); ?> <?php echo app_lang("gd_primary"); ?></div></div></div>
