    <?php if ($id) { ?><div class="form-group"><div class="row"><label class="col-md-3 text-danger"><?php echo app_lang("gd_delete_reason"); ?></label><div class="col-md-9"><?php echo form_input(["name" => "reason", "class" => "form-control", "maxlength" => 500]); ?></div></div></div><?php } ?>
</div></div>
<div class="modal-footer"><?php if ($id) { ?><button type="button" id="gd-delete-address" class="btn btn-danger me-auto"><?php echo app_lang("delete"); ?></button><?php } ?><button type="button" class="btn btn-default" data-bs-dismiss="modal"><?php echo app_lang("close"); ?></button><button type="submit" class="btn btn-primary"><?php echo app_lang("save"); ?></button></div><?php echo form_close(); ?>
<script type="text/javascript">
$(document).ready(function () { var form = $("#gd-address-form"); form.appForm({onSuccess: function () { location.reload(); }, onError: function (result) { if (result.duplicate_confirmation_required && window.confirm('<?php echo addslashes(app_lang("gd_confirm_duplicate_override")); ?>')) { form.find("[name=duplicate_override]").val("1"); setTimeout(function () { form.trigger("submit"); }, 100); } return true; }}); $("#gd-delete-address").click(function () { if (!form.find("[name=reason]").val()) { appAlert.error('<?php echo addslashes(app_lang("gd_delete_reason_required")); ?>', {container: ".modal-body", animate: false}); return; } $.post('<?php echo_uri("grupo_donato/addresses/delete"); ?>', form.serialize(), function (result) { if (result.success) location.reload(); else appAlert.error(result.message, {container: ".modal-body", animate: false}); }, "json"); }); });
</script>
